using BgControls.Windows.Controls;using BgControls.Windows.DragDrop;using BgControls.Windows.Shapes;namespace BgControls.Windows.Input.Touch;/// <summary>/// 触控状态指示器控件，用于在触控交互时提供视觉反馈./// </summary>[TemplatePart(Name = OuterArcPart, Type = typeof(Arc))][TemplatePart(Name = InnerArcPart, Type = typeof(Arc))]public class TouchIndicator : Control{    private const string InnerArcPart = "PART_InnerArc";    private const string OuterArcPart = "PART_OuterArc";    private const int PlayAnimationDelay = 200;    private const int InnerAnimationDuration = 200;    private const int OuterAnimationDuration = 300;    private const int TapAndMoveWaitInterval = 600;    private const int InnerArcSize = 74;    private const int OuterArcSize = 100;    private const int InnerArcMargin = 23;    private const int OuterArcMargin = 10;    /// <summary>    /// Initializes static members of the <see cref="TouchIndicator"/> class.    /// </summary>    static TouchIndicator()    {        DefaultStyleKeyProperty.OverrideMetadata(typeof(TouchIndicator), new FrameworkPropertyMetadata(typeof(TouchIndicator)));    }    private readonly DispatcherTimer playTapAndMoveAnimationTimer;    private readonly DispatcherTimer playTapAndHoldAnimationTimer;    private readonly Popup popup;    private Storyboard? innerArcStoryboard;    private Storyboard? outerArcStoryboard;    private Arc? innerArc;    private Arc? outerArc;    private bool hasAppliedTemplate;    private TouchIndicatorState currentState;    private bool canBeTapAndHold;    private bool canBeTapAndMove;    private DateTime startDateTime;    private AdornerLayer? adornerLayer;    private BgControls.Windows.DragDrop.DragHelper.UIElementAdorner? adorner;    /// <summary>    /// Initializes a new instance of the <see cref="TouchIndicator"/> class.    /// </summary>    public TouchIndicator()    {        this.popup = new Popup();        this.Focusable = false;        this.popup.Child = this;        this.hasAppliedTemplate = false;        // 初始化点击并移动的动画计时器.        this.playTapAndMoveAnimationTimer = new DispatcherTimer();        this.playTapAndMoveAnimationTimer.Tick += (sender, e) =>        {            if (this.hasAppliedTemplate && this.innerArcStoryboard != null)            {                this.innerArcStoryboard.Begin();            }        };        // 初始化点击并按住的动画计时器.        this.playTapAndHoldAnimationTimer = new DispatcherTimer();        this.playTapAndHoldAnimationTimer.Tick += (sender, e) =>        {            if (this.hasAppliedTemplate && this.outerArcStoryboard != null)            {                this.outerArcStoryboard.Begin();            }        };    }    /// <summary>    /// Gets 当前指示器的状态.    /// </summary>    internal TouchIndicatorState CurrentState => this.currentState;    /// <summary>    /// 初始化控件.    /// </summary>    /// <param name="e">事件参数.</param>    protected override void OnInitialized(EventArgs e)    {        base.OnInitialized(e);    }    /// <summary>    /// 应用控件模板时的处理逻辑.    /// </summary>    public override void OnApplyTemplate()    {        base.OnApplyTemplate();        this.innerArc = this.GetTemplateChildOfType<Arc>(InnerArcPart);        this.outerArc = this.GetTemplateChildOfType<Arc>(OuterArcPart);        this.SetMetrics();        this.InitializeStoryboards();        this.hasAppliedTemplate = true;    }    /// <summary>    /// 显示指示器.    /// </summary>    /// <param name="owner">所有者元素.</param>    /// <param name="position">显示位置坐标.</param>    internal void Show(UIElement owner, Point position)    {        ArgumentNullException.ThrowIfNull(owner, nameof(owner));        this.currentState = TouchIndicatorState.Undefined;        double offset = 60.0;        bool usePopup = ApplicationHelper.IsFullTrust;        if (usePopup)        {            this.popup.AllowsTransparency = true;            usePopup = this.popup.AllowsTransparency;        }        if (usePopup)        {            // 在高权限/完全信任模式下使用弹出窗口显示.            Point screenPosition = ApplicationHelper.GetDpiAwarePositionOnScreen(owner, position);            this.popup.AllowsTransparency = true;            this.popup.Placement = System.Windows.Controls.Primitives.PlacementMode.Absolute;            this.popup.HorizontalOffset = screenPosition.X - offset;            this.popup.VerticalOffset = screenPosition.Y - offset;            this.popup.IsOpen = true;        }        else        {            // 在受限模式下使用装饰层显示.            if (!(DragOperation.GetRootVisual(owner) is UIElement visual))            {                throw new ArgumentException("owner should have UIElement as parent in the visual tree.");            }            this.adornerLayer = AdornerLayer.GetAdornerLayer(visual);            if (this.adornerLayer != null)            {                if (this.adorner == null)                {                    this.adorner = new BgControls.Windows.DragDrop.DragHelper.UIElementAdorner(this, owner);                }                this.adorner.LeftOffset = position.X - offset;                this.adorner.TopOffset = position.Y - offset;                this.adornerLayer.Add(this.adorner);            }        }        this.startDateTime = DateTime.UtcNow;    }    /// <summary>    /// 隐藏指示器并计算当前状态.    /// </summary>    internal void Hide()    {        if (this.popup.IsOpen)        {            double totalMilliseconds = (DateTime.UtcNow - this.startDateTime).TotalMilliseconds;            if (this.canBeTapAndHold && totalMilliseconds > (double)TouchManager.TapTime)            {                this.currentState = TouchIndicatorState.TapAndHold;            }            else if (this.canBeTapAndMove && totalMilliseconds > (double)TapAndMoveWaitInterval)            {                this.currentState = TouchIndicatorState.TapAndMove;            }            else            {                this.currentState = TouchIndicatorState.Undefined;            }            this.canBeTapAndHold = false;            this.canBeTapAndMove = false;            this.popup.IsOpen = false;        }        if (this.adornerLayer != null && this.adorner != null)        {            this.adornerLayer.Remove(this.adorner);        }        this.adornerLayer = null;        this.StopTapAndMoveAnimation();        this.StopTapAndHoldAnimation();    }    /// <summary>    /// 显示“点击并移动”指示动画.    /// </summary>    internal void ShowTabAndMoveIndicator()    {        int delay = 400 - (int)(DateTime.UtcNow - this.startDateTime).TotalMilliseconds;        if (delay >= 0)        {            this.PlayTapAndMoveAnimation(delay);            this.canBeTapAndMove = true;        }    }    /// <summary>    /// 显示“点击并按住”指示动画.    /// </summary>    internal void ShowTapAndHoldIndicator()    {        TimeSpan elapsed = DateTime.UtcNow - this.startDateTime;        int delay = TouchManager.TapTime - 300 - (int)elapsed.TotalMilliseconds;        if (delay >= 0)        {            this.PlayTapAndHoldAnimation(delay);            this.canBeTapAndHold = true;        }    }    /// <summary>    /// 初始化内部圆弧与外部圆弧的动画资源.    /// </summary>    private void InitializeStoryboards()    {        // 初始化内部圆弧动画.        this.innerArcStoryboard = new Storyboard();        DoubleAnimationUsingKeyFrames innerAnimation = new DoubleAnimationUsingKeyFrames();        Storyboard.SetTargetProperty(innerAnimation, new PropertyPath(Arc.EndAngleProperty));        Storyboard.SetTarget(innerAnimation, this.innerArc);        EasingDoubleKeyFrame innerKeyFrame = new EasingDoubleKeyFrame        {            Value = 360.0,            KeyTime = KeyTime.FromTimeSpan(TimeSpan.FromMilliseconds(InnerAnimationDuration)),            EasingFunction = new ExponentialEase { EasingMode = EasingMode.EaseIn }        };        innerAnimation.KeyFrames.Add(innerKeyFrame);        this.innerArcStoryboard.Children.Add(innerAnimation);        // 初始化外部圆弧动画.        this.outerArcStoryboard = new Storyboard();        DoubleAnimationUsingKeyFrames outerAnimation = new DoubleAnimationUsingKeyFrames();        Storyboard.SetTargetProperty(outerAnimation, new PropertyPath(Arc.EndAngleProperty));        Storyboard.SetTarget(outerAnimation, this.outerArc);        EasingDoubleKeyFrame outerKeyFrame = new EasingDoubleKeyFrame        {            Value = 360.0,            KeyTime = KeyTime.FromTimeSpan(TimeSpan.FromMilliseconds(OuterAnimationDuration)),            EasingFunction = new ExponentialEase { EasingMode = EasingMode.EaseIn }        };        outerAnimation.KeyFrames.Add(outerKeyFrame);        this.outerArcStoryboard.Children.Add(outerAnimation);    }    /// <summary>    /// 获取模板中的子控件并确保其类型正确.    /// </summary>    private T GetTemplateChildOfType<T>(string name) where T : DependencyObject    {        T? child = this.GetTemplateChild(name) as T;        if (child == null)        {            throw new NotSupportedException($"Template part {name} of type {typeof(T).Name} is required.");        }        return child;    }    /// <summary>    /// 停止“点击并移动”的动画效果.    /// </summary>    private void StopTapAndMoveAnimation()    {        if (this.hasAppliedTemplate && this.innerArcStoryboard != null)        {            this.playTapAndMoveAnimationTimer.Stop();            this.innerArcStoryboard.Remove();        }    }    /// <summary>    /// 停止“点击并按住”的动画效果.    /// </summary>    private void StopTapAndHoldAnimation()    {        if (this.hasAppliedTemplate && this.outerArcStoryboard != null)        {            this.playTapAndHoldAnimationTimer.Stop();            this.outerArcStoryboard.Remove();        }    }    /// <summary>    /// 设置圆弧的基础度量参数.    /// </summary>    private void SetMetrics()    {        if (this.innerArc != null)        {            this.innerArc.Height = InnerArcSize;            this.innerArc.Width = InnerArcSize;            this.innerArc.Margin = new Thickness(InnerArcMargin);            this.innerArc.Diameter = InnerArcSize;        }        if (this.outerArc != null)        {            this.outerArc.Height = OuterArcSize;            this.outerArc.Width = OuterArcSize;            this.outerArc.Margin = new Thickness(OuterArcMargin);            this.outerArc.Diameter = OuterArcSize;        }    }    /// <summary>    /// 延时执行“点击并移动”动画.    /// </summary>    private void PlayTapAndMoveAnimation(int delay)    {        this.playTapAndMoveAnimationTimer.Interval = TimeSpan.FromMilliseconds(delay);        this.playTapAndMoveAnimationTimer.Start();    }    /// <summary>    /// 延时执行“点击并按住”动画.    /// </summary>    private void PlayTapAndHoldAnimation(int delay)    {        this.playTapAndHoldAnimationTimer.Interval = TimeSpan.FromMilliseconds(delay);        this.playTapAndHoldAnimationTimer.Start();    }}